class BankAccount:
    """Abstract interface for a bank account - hides implementation details"""

    def __init__(self, account_holder: str, initial_balance: float = 0.0):
        self._account_holder = account_holder  # Private internal data
        self.__balance = initial_balance  # Hidden implementation (name mangling)
        self.__transactions = []  # Hidden transaction history

    def deposit(self, amount: float) -> dict:
        """Public interface - users don't need to know validation logic"""
        if amount <= 0:
            return {"success": False, "message": "Amount must be positive"}

        self.__balance += amount
        self.__record_transaction("DEPOSIT", amount)
        return {"success": True, "new_balance": self.__balance}

    def withdraw(self, amount: float) -> dict:
        """Public interface - abstraction hides overdraft logic"""
        if amount <= 0:
            return {"success": False, "message": "Amount must be positive"}

        if amount > self.__balance:
            return {"success": False, "message": "Insufficient funds"}

        self.__balance -= amount
        self.__record_transaction("WITHDRAWAL", amount)
        return {"success": True, "new_balance": self.__balance}

    def get_balance(self) -> float:
        """Public interface - returns balance without exposing internal storage"""
        return self.__balance

    def __record_transaction(self, txn_type: str, amount: float) -> None:
        """Private method - completely hidden from external users"""
        self.__transactions.append({
            "type": txn_type,
            "amount": amount,
            "balance_after": self.__balance
        })

# Client code - uses abstraction without knowing implementation
account = BankAccount("John Doe", 1000)
print(account.deposit(500))  # {"success": True, "new_balance": 1500.0}
print(account.withdraw(200))  # {"success": True, "new_balance": 1300.0}
print(account.get_balance())  # 1300.0

