"""Main calculator that uses modular components"""

from operations.basic_operations import BasicOperations
from operations.scientific_operations import ScientificOperations

class Calculator:
    """Facade that combines modular components"""

    def __init__(self):
        self.basic = BasicOperations()
        self.scientific = ScientificOperations()

    def calculate(self, operation: str, *args) -> float:
        operations = {
            "add": self.basic.add,
            "subtract": self.basic.subtract,
            "multiply": self.basic.multiply,
            "divide": self.basic.divide,
            "power": self.scientific.power,
            "sqrt": self.scientific.square_root,
            "log": self.scientific.logarithm,
            "factorial": self.scientific.factorial
        }

        if operation not in operations:
            raise ValueError(f"Unknown operation: {operation}")

        return operations[operation](*args)

# Client code - uses modular system
calc = Calculator()

print("Basic Operations:")
print(f"5 + 3 = {calc.calculate('add', 5, 3)}")
print(f"10 / 2 = {calc.calculate('divide', 10, 2)}")

print("\nScientific Operations:")
print(f"2^8 = {calc.calculate('power', 2, 8)}")
print(f"sqrt(144) = {calc.calculate('sqrt', 144)}")
print(f"5! = {calc.calculate('factorial', 5)}")

from abc import ABC, abstractmethod
from typing import Dict

# File: payment_gateway.py
"""Abstract interface - defines contract for all payment methods"""

class PaymentGateway(ABC):
    """Abstraction layer - defines what payment methods must implement"""

    @abstractmethod
    def process_payment(self, amount: float, currency: str = "INR") -> Dict:
        pass

    @abstractmethod
    def refund(self, transaction_id: str, amount: float) -> Dict:
        pass

# File: concrete_payments.py
"""Concrete implementations - independent modules"""

class CreditCardPayment(PaymentGateway):
    def __init__(self, card_number: str, cvv: str):
        self.card_number = card_number[-4:].rjust(16, '*')
        self.cvv = cvv

    def process_payment(self, amount: float, currency: str = "INR") -> Dict:
        # Integration with credit card API would go here
        return {
            "status": "success",
            "method": "Credit Card",
            "card": self.card_number,
            "amount": amount,
            "currency": currency,
            "transaction_id": f"CC-{hash((amount, self.card_number)) % 100000}"
        }

    def refund(self, transaction_id: str, amount: float) -> Dict:
        return {
            "status": "refund_success",
            "method": "Credit Card",
            "transaction_id": transaction_id,
            "refund_amount": amount
        }

