"""High-level module - depends on abstraction, not concrete implementations"""

class OrderProcessor:
    """Independent of concrete payment methods - depends on abstraction"""

    def __init__(self, payment_gateway: PaymentGateway):
        # Dependency injection - payment method is injected from outside
        self.payment_gateway = payment_gateway

    def process_order(self, order_id: str, amount: float) -> Dict:
        # Order processing logic
        print(f"Processing order {order_id} for amount {amount}")

        # Payment is handled by injected gateway - no dependency on concrete class
        payment_result = self.payment_gateway.process_payment(amount)

        return {
            "order_id": order_id,
            "payment": payment_result,
            "order_status": "confirmed"
        }

    def process_refund(self, transaction_id: str, amount: float) -> Dict:
        return self.payment_gateway.refund(transaction_id, amount)

# Client code - can switch payment methods without changing OrderProcessor
print("=== Using Credit Card ===")
cc_payment = CreditCardPayment("4532123456789012", "123")
processor = OrderProcessor(cc_payment)
result = processor.process_order("ORD-001", 2500.00)
print(result)

print("\n=== Switching to PayPal (no code changes to OrderProcessor) ===")
pp_payment = PayPalPayment("user@paypal.com")
processor = OrderProcessor(pp_payment)  # Same processor, different payment
result = processor.process_order("ORD-002", 1500.00)
print(result)

print("\n=== Adding new UPI payment method (Open/Closed Principle) ===")
upi_payment = UPIPayment("merchant@upi")
processor = OrderProcessor(upi_payment)
result = processor.process_order("ORD-003", 500.00)
print(result)
